  END
  CLASS
	NAME "Temperatura mínima (ḞC)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-3 - -2"
    EXPRESSION ([pixel] >= -3 AND [pixel] < -2)
    COLOR 123 0 255
  END
  CLASS
	NAME "-2 - -1"
    EXPRESSION ([pixel] >= -2 AND [pixel] < -1)
    COLOR 42 0 255
  END
  CLASS
	NAME "-1 - 0"
    EXPRESSION ([pixel] >= -1 AND [pixel] < 0)
    COLOR 0 111 255
  END
  CLASS
	NAME "0 - 1"
    EXPRESSION ([pixel] >= 0 AND [pixel] < 1)
    COLOR 0 156 235
  END
  CLASS
	NAME "1 - 2"
    EXPRESSION ([pixel] >= 1 AND [pixel] < 2)
    COLOR 105 180 255
  END
  CLASS
	NAME "2 - 3"
    EXPRESSION ([pixel] >= 2 AND [pixel] <= 4)
    COLOR 33 192 255
  END
END # Layer